const parser = require('@babel/parser');
const traverse = require('@babel/traverse').default;

const { astCache } = require('../../cache/ast-cache');

const DECLARATION_TYPES = [
  'BooleanLiteral',
  'StringLiteral',
  'ArrayExpression',
];

const BOOTSTRAP_FUNCTION_NAME = 'onBootstrapPage';
const HYDRATE_ISLANDS = 'islands';

/**
 * @typedef { Array<babel.NodePath['node']> | string | boolean | number | undefined } DeclarationValue
 */

/**
 * @param {babel.NodePath} nodePath
 * @param {Record<string, DeclarationValue>} declarationValues
 */
const validateAndRegisterBootstrapReexport = (nodePath, declarationValues) => {
  if (nodePath.node.exported?.name === BOOTSTRAP_FUNCTION_NAME) {
    declarationValues[nodePath.node.exported?.name] = true;
  }
};

/**
 * @param {babel.NodePath<babel.types.ExportDefaultSpecifier | babel.types.ExportNamespaceSpecifier | babel.types.ExportSpecifier>} specifierPath
 * @param {Array<string>} declarationNames
 * @param {Record<string, DeclarationValue>} declarationValues
 */
const getDeclarationValueFromSpecifier = (
  specifierPath,
  declarationNames,
  declarationValues,
) => {
  validateAndRegisterBootstrapReexport(specifierPath, declarationValues);

  const { node: nodeExported } = specifierPath;

  if (!declarationNames.includes(nodeExported.exported.name)) {
    return;
  }

  const bindingIdentifier = specifierPath.scope.getBinding(
    nodeExported.local.name,
  );

  const parentNode = bindingIdentifier.path?.parentPath?.node;

  const [variableDeclarator] = parentNode.declarations;

  if (!DECLARATION_TYPES.includes(variableDeclarator.init?.type)) {
    return;
  }

  declarationValues[variableDeclarator.id.name] =
    typeof variableDeclarator.init.value === 'undefined'
      ? variableDeclarator.init.elements
      : variableDeclarator.init.value;
};

/**
 * @param {string} sourceCode
 */
const parseSourceCode = (sourceCode) =>
  parser.parse(sourceCode, {
    plugins: ['jsx', 'typescript'],
    sourceType: 'module',
  });

/**
 * Enforces the rules for exporting onBootstrapPage.
 * @param {Record<string, DeclarationValue>} declarationValues
 */
const enforceBootstrapPageRules = (declarationValues) => {
  if (!(BOOTSTRAP_FUNCTION_NAME in declarationValues)) {
    return;
  }

  const hydrateValue =
    typeof declarationValues.hydrate === 'undefined' ||
    declarationValues.hydrate;

  if (hydrateValue !== HYDRATE_ISLANDS && hydrateValue !== false) {
    // eslint-disable-next-line @typescript-eslint/no-dynamic-delete
    delete declarationValues[BOOTSTRAP_FUNCTION_NAME];
  }
};

/**
 * Get the value of the export declaration by name.
 * @param {parser.ParseResult<babel.types.File>} ast
 * @param {Array<string>} declarationNames
 */
const getExportValues = (ast, declarationNames) => {
  /** @type {Record<string, DeclarationValue>} */
  const declarationValues = {};

  traverse(ast, {
    ExportNamedDeclaration(path) {
      validateAndRegisterBootstrapReexport(path, declarationValues);

      if (path.node.declaration?.id?.name === BOOTSTRAP_FUNCTION_NAME) {
        declarationValues[path.node.declaration?.id?.name] = true;
      }

      if (path.node.declaration?.declarations) {
        const { declarations: nodeDeclarations } = path.node.declaration;

        nodeDeclarations.forEach((declaration) => {
          if (declaration.id.name === BOOTSTRAP_FUNCTION_NAME) {
            declarationValues[declaration.id.name] = true;
          }

          if (
            declarationNames.includes(declaration.id.name) &&
            typeof declaration.init.value !== 'undefined'
          ) {
            declarationValues[declaration.id.name] = declaration.init.value;
          }
        });
      }
    },
    ExportSpecifier(path) {
      getDeclarationValueFromSpecifier(
        path,
        declarationNames,
        declarationValues,
      );
    },
  });

  enforceBootstrapPageRules(declarationValues);

  return declarationValues;
};

/**
 * Get the value of the export declaration from a file by name.
 * @param {string} filePath
 * @param {Array<string>} declarationNames
 */
const getExportsFromFile = (filePath, declarationNames) => {
  const ast = astCache.getAstByFilePath(filePath);

  return getExportValues(ast, declarationNames);
};

module.exports = { getExportsFromFile, parseSourceCode };
